import { useQuery } from "@tanstack/react-query";
import { useGetOneQueryOptions } from "../../../query-helpers/useGetOneQueryOptions";
import type {
  PublicAccountAssociationResponse,
  PublicAccountResponse,
} from "../../../types/accounts";
import { accountQueryKeys } from "./queryKeys";

type UseGetAccountParams = {
  /** Account UID to retrieve */
  accountUid: string;
  /** Whether to include associations (analytics config, account config) */
  includeAssociations?: boolean;
};

type UseGetAccountOptions = {
  enabled?: boolean;
  staleTime?: number;
  cacheTime?: number;
};

/**
 * Hook to fetch public account information
 * @param params - Account UID and optional association flag
 * @param options - Query options
 * @returns Query result with account data
 */
export const useGetAccountQueryOptions = ({
  accountUid,
  includeAssociations = false,
  ...options
}: UseGetAccountParams & UseGetAccountOptions) => {
  const queryParams = new URLSearchParams();

  if (includeAssociations) {
    queryParams.set("view", "association");
  }

  const endpoint = `/accounts/${accountUid}${queryParams.toString() ? `?${queryParams.toString()}` : ""}`;

  return useGetOneQueryOptions<
    typeof includeAssociations extends true
      ? PublicAccountAssociationResponse
      : PublicAccountResponse
  >(
    endpoint,
    {},
    accountQueryKeys.entity({
      namespace: "public",
      parameters: { accountUid, includeAssociations },
    }).queryKey,
    {
      namespace: "public",
      staleTime: 300000, // 5 minutes - account info doesn't change frequently
      ...options,
    },
  );
};

/**
 * Hook to fetch basic public account information
 * @param params - Account UID
 * @param options - Query options
 * @returns Query result with basic account data
 */
export const useGetAccount = ({
  accountUid,
  ...options
}: UseGetAccountParams & UseGetAccountOptions) => {
  return useQuery(
    useGetAccountQueryOptions({
      accountUid,
      includeAssociations: false,
      ...options,
    }),
  );
};

/**
 * Hook to fetch public account information with associations
 * @param params - Account UID
 * @param options - Query options
 * @returns Query result with account data including analytics and configuration
 */
export const useGetAccountWithAssociations = ({
  accountUid,
  ...options
}: Omit<UseGetAccountParams, "includeAssociations"> & UseGetAccountOptions) => {
  return useQuery(
    useGetAccountQueryOptions({
      accountUid,
      includeAssociations: true,
      ...options,
    }),
  );
};

