2. Your params are already **required strings**, so `slug || ""` and `token || ""` are unnecessary and hide real bugs. If a param is missing, you should fail fast.

Here’s the corrected loader shape:

```ts
export const Route = createFileRoute("/lead/$slug/$token")({
  component: RouteComponent,
  loader: async ({ params, context }) => {
    const { queryClient } = context;
    const { slug, token } = params;

    const actionPage = await queryClient.fetchQuery(
      useGetPublicActionPageQueryOptions({
        actionPageSlug: slug,
        accountSlug: token,
      }),
    );

    const account = await queryClient.fetchQuery(
      useGetAccountQueryOptions({
        accountUid: actionPage.account.id,
      }),
    );

    return { actionPage, account };
  },
});
```

If your `slug`/`token` mapping is actually reversed for the API, swap those two fields—but don’t use empty-string fallbacks. That’s what’s tripping types and masking the real issue.
